<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <OutputType>Exe</OutputType>
    <TargetFramework>net8.0</TargetFramework>
  </PropertyGroup>
  <ItemGroup>
    <PackageReference Include="xunit.v3" Version="3.2.2" />
  </ItemGroup>
</Project>
EOF
cat > Program.cs << 'EOF'
using System;
using System.Linq;
using System.Reflection;

var coreAsm = AppDomain.CurrentDomain.GetAssemblies()
    .FirstOrDefault(a => a.GetName().Name == "xunit.v3.core");

if (coreAsm == null) {
    // Load from file
    var path = System.IO.Path.Combine(
        Environment.GetFolderPath(Environment.SpecialFolder.UserProfile),
        ".nuget/packages/xunit.v3.extensibility.core/3.2.2/lib/netstandard2.0/xunit.v3.core.dll");
    coreAsm = Assembly.LoadFrom(path);
}

foreach (var t in coreAsm.GetExportedTypes().OrderBy(t => t.FullName)) {
    if (t.Name.Contains("ITestCaseOrderer") && !t.Name.Contains("Attribute")) {
        Console.WriteLine($"Interface: {t.FullName}");
        foreach (var m in t.GetMethods()) {
            Console.WriteLine($"  {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
        }
    }
}

// Also check CollectionBehavior attribute constructors
var cbType = coreAsm.GetExportedTypes().FirstOrDefault(t => t.Name == "CollectionBehaviorAttribute");
if (cbType != null) {
    Console.WriteLine($"\nCollectionBehaviorAttribute constructors:");
    foreach (var c in cbType.GetConstructors()) {
        Console.WriteLine($"  ({string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    }
}

// Check TestCaseOrdererAttribute constructors
var tcoType = coreAsm.GetExportedTypes().FirstOrDefault(t => t.Name == "TestCaseOrdererAttribute");
if (tcoType != null) {
    Console.WriteLine($"\nTestCaseOrdererAttribute constructors:");
    foreach (var c in tcoType.GetConstructors()) {
        Console.WriteLine($"  ({string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    }
}
EOF
